def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.sqrt(np.sum((point1 - point2) ** 2))

    def calculate_travel_time(start, end):
        return calculate_distance(start, end) / truck_speed

    def expected_time_penalty(index, travel_time, wait_time):
        return travel_time + wait_time * 0.5  # Emphasize lower wait times

    best_node = None
    min_expected_penalty = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_time
        time_window_start, time_window_end = time_windows[i]

        # Calculate expected wait or delay penalty
        if arrival_time < time_window_start:
            wait_time = time_window_start - arrival_time
        elif arrival_time > time_window_end:
            wait_time = (arrival_time - time_window_end) ** 2
        else:
            wait_time = 0  # No penalty for being perfectly within the time window

        expected_penalty = expected_time_penalty(i, travel_time, wait_time)

        # Update best node based on minimum expected penalty
        if expected_penalty < min_expected_penalty:
